#!/usr/bin/env powershell # Script para ejecutar la aplicación InazumaGo
param( [switch]$Console, [switch]$Help )
if ($Help) { Write-Host "Uso: .\run-app.ps1 [opciones]" Write-Host "" Write-Host "Opciones:" Write-Host " -Console Ejecutar en modo CLI (sin GUI)" Write-Host " -Help Mostrar esta ayuda" Write-Host "" Write-Host "Ejemplos:" Write-Host " .\run-app.ps1 # Ejecutar en modo GUI" Write-Host " .\run-app.ps1 -Console # Ejecutar en modo CLI" exit 0 }
$ErrorActionPreference = "Stop"
# Verificar que Maven compile ha sido ejecutado if (-not (Test-Path "target/classes")) { Write-Host "❌ Error: target/classes no existe" Write-Host "" Write-Host "Primero compila el proyecto:" Write-Host " mvn clean compile" exit 1 }
# Verificar que dependencias han sido descargadas if (-not (Test-Path "target/dependency")) { Write-Host "❌ Error: target/dependency no existe" Write-Host "" Write-Host "Primero descarga las dependencias:" Write-Host " mvn dependency:copy-dependencies" exit 1 }
# Construir lista de archivos JAR $jars = @(Get-ChildItem -Path "target/dependency" -Filter "*.jar" -ErrorAction SilentlyContinue | Select-Object -ExpandProperty FullName)
# Construir el classpath $classPath = "target/classes" + ";" + ($jars -join ";")
# Argumentos base $args = @("-cp", $classPath)
# Añadir argumentos de aplicación if ($Console) { Write-Host "Ejecutando en modo CLI..." $args += @("es.iesquevedo.Main", "console") } else { Write-Host "Ejecutando en modo GUI..." Write-Host "Se abrirá una ventana JavaFX..." $args += "es.iesquevedo.Main" }
Write-Host ""
# Ejecutar Java & java $args
if ($LASTEXITCODE -ne 0) { Write-Host "" Write-Host "❌ Error al ejecutar la aplicación (código: $LASTEXITCODE)" exit $LASTEXITCODE }

#!/usr/bin/env powershell
# Script para ejecutar la aplicación InazumaGo

param(
    [switch]$Console,
    [switch]$Help
)

if ($Help) {
    Write-Host "Uso: .\run-app.ps1 [opciones]"
    Write-Host ""
    Write-Host "Opciones:"
    Write-Host "  -Console  Ejecutar en modo CLI (sin GUI)"
    Write-Host "  -Help     Mostrar esta ayuda"
    Write-Host ""
    Write-Host "Ejemplos:"
    Write-Host "  .\run-app.ps1              # Ejecutar en modo GUI"
    Write-Host "  .\run-app.ps1 -Console     # Ejecutar en modo CLI"
    exit 0
}

$ErrorActionPreference = "Stop"

# Verificar que Maven compile ha sido ejecutado
if (-not (Test-Path "target/classes")) {
    Write-Host "❌ Error: target/classes no existe"
    Write-Host ""
    Write-Host "Primero compila el proyecto:"
    Write-Host "  mvn clean compile"
    exit 1
}

# Construir el classpath
$classpath = "target/classes"

# Añadir todos los JARs de target/dependency
if (Test-Path "target/dependency") {
    Get-ChildItem -Path "target/dependency" -Filter "*.jar" | ForEach-Object {
        $classpath += ";$($_.FullName)"
    }
} else {
    Write-Host "⚠️  Advertencia: target/dependency no existe"
    Write-Host "La aplicación puede necesitar más dependencias."
    Write-Host ""
}

# Argumentos
$javaArgs = @(
    "-cp", $classpath,
    "--add-modules", "javafx.controls,javafx.fxml",
    "--add-opens", "javafx.graphics/com.sun.javafx.application=ALL-UNNAMED",
    "es.iesquevedo.Main"
)

if ($Console) {
    Write-Host "Ejecutando en modo CLI..."
    $javaArgs += "console"
} else {
    Write-Host "Ejecutando en modo GUI..."
    Write-Host "Se abrirá una ventana JavaFX..."
}

Write-Host ""

# Ejecutar Java
& java $javaArgs

if ($LASTEXITCODE -ne 0) {
    Write-Host ""
    Write-Host "❌ Error al ejecutar la aplicación (código: $LASTEXITCODE)"
    exit $LASTEXITCODE
}

package es.iesquevedo;

import es.iesquevedo.config.AppConfig;
import es.iesquevedo.controller.HealthController;
import es.iesquevedo.controller.MainController;
import es.iesquevedo.service.impl.MainServiceImpl;
import es.iesquevedo.ui.HealthUIAdapter;
import es.iesquevedo.ui.UIAdapter;
import es.iesquevedo.util.DateUtils;

import java.util.logging.Level;
import java.util.logging.Logger;

public class Main {
    private static final Logger LOGGER = Logger.getLogger(Main.class.getName());

    public static void main(String[] args) {
        // Configuración mínima: preferir URL de Firebase desde la variable de entorno FIREBASE_URL
        String firebaseUrl = System.getenv("FIREBASE_URL");

        // Crear repositorio (Firebase si FIREBASE_URL está definido, sino InMemory)
        var repository = AppConfig.createMainRepository(firebaseUrl);

        // Crear servicio y controlador
        var service = new MainServiceImpl(repository);
        var mainController = new MainController(service);

        // Adaptadores UI
        var ui = new UIAdapter(mainController);
        var healthController = new HealthController();
        var healthUi = new HealthUIAdapter(healthController);

        // Uso simple: saludar y comprobar estado
        // Comprobar explícitamente si el nivel está habilitado y usar el formateo incorporado
        if (LOGGER.isLoggable(Level.INFO)) {
            LOGGER.log(Level.INFO, "{0} {1}", new Object[]{DateUtils.nowIso(), ui.greet()});
            LOGGER.log(Level.INFO, "{0} Health: {1}", new Object[]{DateUtils.nowIso(), healthUi.health()});
        }
    }
}

package es.iesquevedo;

/**
 * Wrapper para MainApp.
 * La lógica principal está en MainApp.java
 */
public class Main {
    public static void main(String[] args) {
        MainApp.main(args);
    }
}

package es.iesquevedo;

import es.iesquevedo.config.AppConfig;
import es.iesquevedo.controller.HealthController;
import es.iesquevedo.controller.MainController;
import es.iesquevedo.service.impl.MainServiceImpl;
import es.iesquevedo.ui.HealthUIAdapter;
import es.iesquevedo.ui.UIAdapter;
import es.iesquevedo.util.DateUtils;
import javafx.application.Application;

import java.util.logging.Level;
import java.util.logging.Logger;

public class MainApp {
    private static final Logger LOGGER = Logger.getLogger(MainApp.class.getName());

    public static void main(String[] args) {
        // Modo console: si se proporciona argumento "console", ejecutar en modo CLI
        if (args.length > 0 && "console".equals(args[0])) {
            runConsoleMode();
            System.exit(0);
        } else {
            // Modo GUI: lanzar aplicación JavaFX
            try {
                Application.launch(MainGUI.class, args);
            } catch (Exception e) {
                LOGGER.log(Level.SEVERE, "Error al iniciar JavaFX", e);
                System.exit(1);
            }
        }
    }

    private static void runConsoleMode() {
        // Configuración mínima: preferir URL de Firebase desde la variable de entorno FIREBASE_URL
        String firebaseUrl = System.getenv("FIREBASE_URL");

        // Crear repositorio (Firebase si FIREBASE_URL está definido, sino InMemory)
        var repository = AppConfig.createMainRepository(firebaseUrl);

        // Crear servicio y controlador
        var service = new MainServiceImpl(repository);
        var mainController = new MainController(service);

        // Adaptadores UI
        var ui = new UIAdapter(mainController);
        var healthController = new HealthController();
        var healthUi = new HealthUIAdapter(healthController);

        // Uso simple: saludar y comprobar estado
        if (LOGGER.isLoggable(Level.INFO)) {
            LOGGER.log(Level.INFO, "{0} {1}", new Object[]{DateUtils.nowIso(), ui.greet()});
            LOGGER.log(Level.INFO, "{0} Health: {1}", new Object[]{DateUtils.nowIso(), healthUi.health()});
        }
    }
}

package es.iesquevedo;

import es.iesquevedo.config.AppConfig;
import es.iesquevedo.controller.MainController;
import es.iesquevedo.service.impl.MainServiceImpl;
import javafx.application.Application;
import javafx.fxml.FXMLLoader;
import javafx.scene.Parent;
import javafx.scene.Scene;
import javafx.stage.Stage;

import java.util.logging.Level;
import java.util.logging.Logger;

public class MainGUI extends Application {
    private static final Logger LOGGER = Logger.getLogger(MainGUI.class.getName());

    @Override
    public void start(Stage primaryStage) {
        try {
            // Configuración de servicios
            String firebaseUrl = System.getenv("FIREBASE_URL");
            var repository = AppConfig.createMainRepository(firebaseUrl);
            var mainService = new MainServiceImpl(repository);

            // Crear controlador
            MainController mainController = new MainController(mainService);

            // Cargar FXML
            FXMLLoader loader = new FXMLLoader(getClass().getResource("/fxml/Main.fxml"));
            loader.setController(mainController);
            Parent root = (Parent) loader.load();

            // Crear escena y mostrar ventana
            Scene scene = new Scene(root, 600, 400);
            primaryStage.setTitle("InazumaGo");
            primaryStage.setScene(scene);
            primaryStage.show();

            if (LOGGER.isLoggable(Level.INFO)) {
                LOGGER.log(Level.INFO, "Aplicación JavaFX iniciada exitosamente");
            }
        } catch (Exception e) {
            LOGGER.log(Level.SEVERE, "Error al iniciar la aplicación", e);
        }
    }
}
